function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

const inputItem = $json || {};
const question = clean(inputItem.input || inputItem.question || inputItem.message || inputItem.text || inputItem.chatInput || inputItem.prompt || "irrigation status at the farm");

return [{
  json: {
    input: question,
    query_type: "status",
    request_url: "https://amadeus-pig-tracking-system.onrender.com/api/telemetry/irrigation/status",
  }
}];

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function num(value) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function fmtMinutes(value) {
  const n = num(value);
  if (n === null) return "unknown minutes";
  return `${Math.round(n)} min`;
}

function fmtScore(value) {
  const n = num(value);
  if (n === null) return "unknown";
  return Number.isInteger(n) ? String(n) : String(Number(n.toFixed(1)));
}

function formatDateTime(iso) {
  if (!iso) return "unknown";
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return iso;
  return new Intl.DateTimeFormat("en-ZA", {
    timeZone: "Africa/Johannesburg",
    year: "numeric",
    month: "short",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  }).format(d);
}

function zoneLabel(name, id) {
  const n = clean(name);
  const z = clean(id);
  if (n && z) return `${n} (${z})`;
  return n || z || "none";
}

function sentence(value) {
  return clean(value).replace(/\s+/g, " ");
}

const route = $("Code - Route Irrigation Question").first()?.json || {};
const question = clean(route.input || "irrigation status at the farm");
const data = $json || {};
const success = data.success === true && data.status === "ok";
let answer = "";

if (!success) {
  const reason = sentence(data.message || data.error || data.operator_summary?.headline || "The irrigation status is not available yet.");
  answer = `I could not read the irrigation status. ${reason}`;
} else {
  const current = data.current || {};
  const today = data.today || {};
  const safety = data.safety || {};
  const rules = data.rules || {};
  const summary = data.operator_summary || {};
  const notes = Array.isArray(summary.notes) ? summary.notes : [];
  const plan = Array.isArray(today.plan) ? today.plan : [];
  const recentEvents = Array.isArray(data.recent_events) ? data.recent_events : [];
  const lines = [];

  lines.push("Irrigation status at Amadeus Farm:");
  lines.push("");
  if (summary.headline) lines.push(sentence(summary.headline));
  lines.push(`Current state: ${sentence(current.status || "unknown")}`);
  lines.push(`Current zone: ${zoneLabel(current.zone_name, current.zone_id)}`);
  lines.push(`Remaining time: ${fmtMinutes(current.remaining_minutes)}`);
  if (current.pause_reason) lines.push(`Pause reason: ${sentence(current.pause_reason)}`);
  if (current.last_update) lines.push(`Last update: ${formatDateTime(current.last_update)}`);
  if (current.last_zone_completed) lines.push(`Last completed zone: ${current.last_zone_completed}`);

  lines.push("");
  lines.push(`Today's plan (${today.date || "unknown date"}):`);
  lines.push(`- Planned zones: ${today.planned_count ?? 0}`);
  lines.push(`- Running: ${today.running_count ?? 0}`);
  lines.push(`- Done: ${today.done_count ?? 0}`);
  lines.push(`- Paused/skipped: ${today.paused_count ?? 0}/${today.skipped_count ?? 0}`);
  lines.push(`- Planned total: ${fmtMinutes(today.total_planned_minutes)}`);
  lines.push(`- Completed: ${fmtMinutes(today.completed_minutes)}`);

  lines.push("");
  lines.push(`Next zone from state: ${zoneLabel(today.state_next_zone_name, today.state_next_zone_id)}`);
  lines.push(`Computed priority next zone: ${zoneLabel(today.computed_next_zone_name, today.computed_next_zone_id)}`);
  if (today.next_zone_mismatch === true) {
    lines.push("Note: the sheet state and computed priority next zone do not match. Treat the state value as the live workflow pointer and review before changing the plan.");
  } else if (today.next_zone_id) {
    lines.push(`Next planned zone: ${zoneLabel(today.next_zone_name, today.next_zone_id)}`);
  }

  if (plan.length > 0) {
    lines.push("");
    lines.push("Plan rows:");
    for (const item of plan.slice(0, 6)) {
      lines.push(`- ${zoneLabel(item.zone_name, item.zone_id)}: ${sentence(item.status || "unknown")}, ${fmtMinutes(item.planned_minutes)}, water score ${fmtScore(item.water_score)}`);
    }
    if (plan.length > 6) lines.push(`- ${plan.length - 6} more row(s) not shown.`);
  }

  const usefulNotes = notes.filter((note) => sentence(note));
  if (usefulNotes.length > 0) {
    lines.push("");
    lines.push("Notes:");
    for (const note of usefulNotes.slice(0, 4)) lines.push(`- ${sentence(note)}`);
  }

  if (recentEvents.length > 0) {
    lines.push("");
    lines.push("Recent irrigation events:");
    for (const event of recentEvents.slice(-3)) {
      lines.push(`- ${formatDateTime(event.timestamp)}: ${sentence(event.event || "event")} ${event.zone_id ? `for ${event.zone_id}` : ""}${event.reason ? ` - ${sentence(event.reason)}` : ""}`.trim());
    }
  }

  lines.push("");
  lines.push("Safety: this is read-only status. It cannot start, stop, or change irrigation.");
  if (safety.hardware_commands_enabled === true || safety.can_control === true || safety.read_only !== true) {
    lines.push("Warning: safety flags are not in the expected read-only state. Do not use this for control decisions until checked.");
  }
  if (rules.wind_pause_kmh !== null || rules.live_rain_skip_mm !== null || rules.rain_forecast_skip_mm_24h !== null) {
    lines.push(`Rules shown: wind pause ${rules.wind_pause_kmh ?? "unknown"} km/h, live rain skip ${rules.live_rain_skip_mm ?? "unknown"} mm, forecast rain skip ${rules.rain_forecast_skip_mm_24h ?? "unknown"} mm.`);
  }

  answer = lines.join("\n");
}

return [{
  json: {
    success,
    input: question,
    query_type: "status",
    answer,
    output: answer,
    irrigation_response: answer,
    telemetry_source: "backend_google_sheets_irrigation_status_read_only",
    backend_payload: data,
  }
}];

